import{_ as i,o as a,c as l,a5 as o}from"./chunks/framework.B5tqjWbr.js";const P=JSON.parse('{"title":"概念：F28075 外设从零配置","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：F28075 外设从零配置","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0047-tms320f28075-peripheral-bringup.html` 的源稿。它只讨论 TI 官方公开资料和教学配置路径，不包含公司内部原理图、引脚分配、真实 PWM 频率、ADC 标定、保护阈值、通信协议或客户项目参数。"},"headers":[],"relativePath":"content/power/concepts/embedded/tms320f28075-peripheral-bringup.md","filePath":"content/power/concepts/embedded/tms320f28075-peripheral-bringup.md","lastUpdated":null}'),r={name:"content/power/concepts/embedded/tms320f28075-peripheral-bringup.md"};function t(c,e,d,n,s,C){return a(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="概念-f28075-外设从零配置" tabindex="-1">概念：F28075 外设从零配置 <a class="header-anchor" href="#概念-f28075-外设从零配置" aria-label="Permalink to &quot;概念：F28075 外设从零配置&quot;">​</a></h1><p>本页是 <code>lessons/0047-tms320f28075-peripheral-bringup.html</code> 的源稿。它只讨论 TI 官方公开资料和教学配置路径，不包含公司内部原理图、引脚分配、真实 PWM 频率、ADC 标定、保护阈值、通信协议或客户项目参数。</p><h2 id="官方资料" tabindex="-1">官方资料 <a class="header-anchor" href="#官方资料" aria-label="Permalink to &quot;官方资料&quot;">​</a></h2><ul><li>TI TMS320F28075 产品页：<code>https://www.ti.com/product/TMS320F28075</code></li><li>TMS320F2807x Real-Time Microcontrollers datasheet：<code>https://www.ti.com/lit/ds/symlink/tms320f28075.pdf</code></li><li>TMS320F2807x Technical Reference Manual：<code>https://www.ti.com/lit/pdf/spruhm9</code></li><li>C2000Ware：<code>https://www.ti.com/tool/C2000WARE</code></li></ul><p>datasheet 用来确认芯片能力、封装、引脚和电气边界；Technical Reference Manual 用来查寄存器和外设工作机制；C2000Ware 用来获取 device support、driverlib、bit-field headers、peripheral examples 和推荐初始化顺序。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>F28075 外设从零配置，是把一个空工程逐步带到可运行 UPS/PCS 控制 ISR 的过程。关键外设包括 ePWM、ADC、Trip Zone、PIE、GPIO、SCI、CAN、SPI、I2C、eCAP、eQEP、CLA、DMA。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>UPS/PCS 控制不是单纯写控制算法。PWM 产生功率级动作，ADC 提供采样证据，Trip Zone 负责硬件快速保护，通信负责调试、BMS 和参数管理，中断系统把这些模块按确定节拍串起来。</p><h2 id="配置顺序" tabindex="-1">配置顺序 <a class="header-anchor" href="#配置顺序" aria-label="Permalink to &quot;配置顺序&quot;">​</a></h2><ol><li>确认芯片和资料版本。</li><li>安装 CCS 与 C2000Ware。</li><li>从空工程到最小 main。</li><li>配置系统时钟、看门狗和 Flash 等待周期。</li><li>配置 GPIO 复用、方向和上拉。</li><li>配置 PIE、中断向量表和 ISR。</li><li>配置 ePWM 时基、比较、动作限定和死区。</li><li>配置 ePWM 触发 ADC SOC。</li><li>配置 ADC 参考、采样窗口、SOC 和 EOC 中断。</li><li>配置 Trip Zone 与过流快速关断。</li><li>配置 SCI、CAN、SPI、I2C 通信外设。</li><li>明确 eCAP、eQEP、CLA、DMA 的使用边界。</li><li>把外设接入 UPS/PCS 控制 ISR。</li></ol><h2 id="关键原则" tabindex="-1">关键原则 <a class="header-anchor" href="#关键原则" aria-label="Permalink to &quot;关键原则&quot;">​</a></h2><ul><li>ePWM 是控制系统的时间基准。</li><li>ADC 采样点要锁定到 PWM 周期里的固定位置。</li><li>Trip Zone 不能等软件保护慢慢判断。</li><li>通信外设不能放进高频控制 ISR 里阻塞等待。</li><li>CLA/DMA 是减轻 CPU 负担，不是替代系统状态机。</li></ul><h2 id="映射表外设的具体配置模板" tabindex="-1">映射表外设的具体配置模板 <a class="header-anchor" href="#映射表外设的具体配置模板" aria-label="Permalink to &quot;映射表外设的具体配置模板&quot;">​</a></h2><h3 id="epwm" tabindex="-1">ePWM <a class="header-anchor" href="#epwm" aria-label="Permalink to &quot;ePWM&quot;">​</a></h3><ul><li>打开时钟：<code>SysCtl_enablePeripheral(SYSCTL_PERIPH_CLK_EPWMx)</code>。</li><li>配置 GPIO 复用：<code>GPIO_setPinConfig(GPIO_x_EPWMx_A/B)</code>。</li><li>设置 <code>TBPRD</code>、<code>CMPA/CMPB</code>、<code>AQCTLA/AQCTLB</code>、<code>DBRED/DBFED</code>。</li><li>DriverLib 入口：<code>EPWM_setTimeBasePeriod()</code>、<code>EPWM_setCounterCompareValue()</code>、<code>EPWM_setActionQualifierAction()</code>、<code>EPWM_setRisingEdgeDeadBandDelayInput()</code>、<code>EPWM_enableADCTrigger()</code>。</li><li>验收：频率、占空比、互补死区、ADC 触发点正确。</li></ul><h3 id="adc" tabindex="-1">ADC <a class="header-anchor" href="#adc" aria-label="Permalink to &quot;ADC&quot;">​</a></h3><ul><li>打开 ADC 时钟并上电。</li><li>配置 SOC：<code>ADC_setupSOC()</code>，对应 <code>ADCSOCxCTL</code>。</li><li>配置 EOC 中断：<code>ADC_setInterruptSource()</code>，对应 <code>ADCINTSEL1N2</code>。</li><li>验收：固定电压源输入时码值线性，EOC 中断频率等于控制频率。</li></ul><h3 id="cmpss-xbar-trip-zone" tabindex="-1">CMPSS/XBAR/Trip Zone <a class="header-anchor" href="#cmpss-xbar-trip-zone" aria-label="Permalink to &quot;CMPSS/XBAR/Trip Zone&quot;">​</a></h3><ul><li>比较器：<code>CMPSS_configHighComparator()</code>、<code>CMPSS_setDACValueHigh()</code>。</li><li>XBAR：<code>XBAR_setEPWMMuxConfig()</code>。</li><li>Trip Zone：<code>EPWM_enableTripZoneSignals()</code> 对应 <code>TZSEL</code>，<code>EPWM_setTripZoneAction()</code> 对应 <code>TZCTL</code>。</li><li>验收：硬件故障注入后 PWM 立即进入安全态。</li></ul><h3 id="sci-can-spi-i2c" tabindex="-1">SCI/CAN/SPI/I2C <a class="header-anchor" href="#sci-can-spi-i2c" aria-label="Permalink to &quot;SCI/CAN/SPI/I2C&quot;">​</a></h3><ul><li>SCI：<code>SCI_setConfig()</code>，用于调试串口和简单上位机命令。</li><li>CAN：<code>CAN_initModule()</code>、<code>CAN_setBitRate()</code>、<code>CAN_setupMessageObject()</code>，用于 BMS、并机和工业通信。</li><li>SPI：<code>SPI_setConfig()</code>，用于外部 ADC、DAC、驱动器或存储器。</li><li>I2C：<code>I2C_setConfig()</code>、<code>I2C_setTargetAddress()</code>，用于 EEPROM、温度传感器和低速配置器件。</li><li>验收：通信异常不会阻塞高频控制 ISR。</li></ul><h3 id="ecap-eqep-cla-dma" tabindex="-1">eCAP/eQEP/CLA/DMA <a class="header-anchor" href="#ecap-eqep-cla-dma" aria-label="Permalink to &quot;eCAP/eQEP/CLA/DMA&quot;">​</a></h3><ul><li>eCAP：<code>ECAP_setEventPolarity()</code> 捕获频率、脉宽和同步信号。</li><li>eQEP：<code>EQEP_setDecoderConfig()</code> 读取编码器或旋转量输入。</li><li>CLA：<code>CLA_mapTaskVector()</code> 把固定数学任务从 CPU ISR 中分出去。</li><li>DMA：<code>DMA_configAddresses()</code> 把重复搬运从 CPU 中分出去。</li><li>验收：触发源、数据边界和 CPU 同步关系清晰。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能说出 datasheet、Technical Reference Manual 和 C2000Ware 的分工。</li><li>能按步骤讲清从空工程到控制 ISR 的 bring-up 顺序。</li><li>能解释 ePWM、ADC、Trip Zone、PIE、SCI/CAN/SPI/I2C 在 UPS/PCS 中的角色。</li><li>能基于控制板原理图列出 PWM、ADC、保护、通信 bring-up 清单。</li></ul><h2 id="复盘问题" tabindex="-1">复盘问题 <a class="header-anchor" href="#复盘问题" aria-label="Permalink to &quot;复盘问题&quot;">​</a></h2><ul><li>PWM 频率不对时，先查哪些时钟链路？</li><li>ADC 抖动时，先查采样点还是控制算法？</li><li>Trip Zone 没有硬件关断时，应该沿哪条链路排查？</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>F28075 或同类 C2000 工程里，控制 ISR 通常由 ePWM 还是 ADC EOC 触发？Trip Zone 保护输入通常来自哪里？只讨论通用架构，不记录内部参数。</p>',30)])])}const p=i(r,[["render",t]]);export{P as __pageData,p as default};
